package com.hospital.management.controller.billing;import com.hospital.management.model.Bill;import com.hospital.management.service.*;import com.hospital.management.service.impl.BillServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/billing/view")public class BillViewServlet extends HttpServlet{private final BillService service;public BillViewServlet(){this(new BillServiceImpl());}public BillViewServlet(BillService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=BillingRequest.id(q.getParameter("id"));Bill b=id==null?null:service.getBill(id,BillingRequest.user(q)).orElse(null);if(b==null){r.sendError(404);return;}q.setAttribute("bill",b);q.getRequestDispatcher("/WEB-INF/views/billing/view.jsp").forward(q,r);}}
